internal class SqliterSqlCursor(private val cursor: Cursor) : SqlCursor {
  override fun getBytes(index: Int): ByteArray? = cursor.getBytesOrNull(index)

  override fun getDouble(index: Int): Double? = cursor.getDoubleOrNull(index)

  override fun getLong(index: Int): Long? = cursor.getLongOrNull(index)

  override fun getString(index: Int): String? = cursor.getStringOrNull(index)

  override fun getBoolean(index: Int): Boolean? {
    return (cursor.getLongOrNull(index) ?: return null) == 1L
  }

  override fun next(): QueryResult.Value<Boolean> = QueryResult.Value(cursor.next())
}

override fun dropAll() {
    KoinPlatformTools.synchronized(this) {
        if (values.isNotEmpty()) {
            val onClose = beanDefinition.callbacks.onClose
            if (onClose != null) {
                // Invoke onClose for each stored instance
                values.values.forEach { v -> onClose.invoke(v) }
            }
            values.clear()
        }
    }
}

internal fun <T> getAll(clazz: KClass<*>, instanceContext: ResolutionContext): List<T> {
    val factories = _instances.values
        .filter { factory ->
            (factory.beanDefinition.scopeQualifier == instanceContext.scope.scopeQualifier ||
                factory.beanDefinition.scopeQualifier == instanceContext.scope.scopeArchetype
            ) &&
            (factory.beanDefinition.primaryType == clazz || factory.beanDefinition.secondaryTypes.contains(clazz))
        }
        .distinct()
//            .sortedWith(compareBy({ it.beanDefinition.toString() }))
    return factories.mapNotNull { it.get(instanceContext) as? T }
}

private fun <T> rawToColumnValue(raw: T?, expression: Expression<T>): T {
    return when {
        raw == null -> null
        raw == NotInitializedValue -> error("$expression is not initialized yet")
        expression is ExpressionWithColumnTypeAlias<T> -> rawToColumnValue(raw, expression.delegate)
        expression is ExpressionAlias<T> -> rawToColumnValue(raw, expression.delegate)
        expression is ExpressionWithColumnType<T> -> expression.columnType.valueFromDB(raw)
        expression is Op.OpBoolean -> BooleanColumnType.INSTANCE.valueFromDB(raw)
        else -> raw
    } as T
}

fun createAndFillValues(data: Map<Expression<*>, Any?>): ResultRow {
    val fieldIndex = HashMap<Expression<*>, Int>(data.size)
    val values = arrayOfNulls<Any?>(data.size)
    data.entries.forEachIndexed { i, columnAndValue ->
        val (column, value) = columnAndValue
        fieldIndex[column] = i
        values[i] = value
    }
    return ResultRow(fieldIndex, values)
}

private fun <T> Column<T>.defaultValueOrNotInitialized(): Any? {
    return when {
        defaultValueFun != null -> when {
            columnType is ColumnWithTransform<*, *> -> {
                (columnType as ColumnWithTransform<Any, Any>).unwrapRecursive(defaultValueFun!!())
            }
            else -> defaultValueFun!!()
        }
        columnType.nullable -> null
        else -> NotInitializedValue
    }
}

private class TimeoutCoroutine<U, in T : U>(
    @JvmField val time: Long,
    uCont: Continuation<U> // unintercepted continuation
) : ScopeCoroutine<T>(uCont.context, uCont), Runnable {
    override fun run() {
        val delay = context.delay
        val name = context[CoroutineName]?.name
        cancelCoroutine(TimeoutCancellationException(time, delay, this, name))
    }

    override fun nameString(): String =
        "${super.nameString()}(timeMillis=$time)"
}

public fun nextUnmarkedIndex(): Int {
    val elementsCount = descriptor.elementsCount
    while (lowerMarks != -1L) {
        val index = lowerMarks.inv().countTrailingZeroBits()
        lowerMarks = lowerMarks or (1L shl index)

        if (readIfAbsent(descriptor, index)) {
            return index
        }
    }

    if (elementsCount > Long.SIZE_BITS) {
        return nextUnmarkedHighIndex()
    }
    return CompositeDecoder.DECODE_DONE
}

internal fun StringBuilder.printQuoted(value: String) {
    append(STRING)
    var lastPos = 0
    for (i in value.indices) {
        val c = value[i].code
        if (c < ESCAPE_STRINGS.size && ESCAPE_STRINGS[c] != null) {
            append(value, lastPos, i) // flush prev
            append(ESCAPE_STRINGS[c])
            lastPos = i + 1
        }
    }

    if (lastPos != 0) append(value, lastPos, value.length)
    else append(value)
    append(STRING)
}

private val tagStack = arrayListOf<Tag>()
    protected val currentTag: Tag
        get() = tagStack.last()
    protected val currentTagOrNull: Tag?
        get() = tagStack.lastOrNull()

    protected fun pushTag(name: Tag) {
        tagStack.add(name)
    }

    @IgnorableReturnValue
    protected fun popTag(): Tag =
        if (tagStack.isNotEmpty())
            tagStack.removeAt(tagStack.lastIndex)
        else
            throw SerializationException("No tag in stack for requested element")

private fun decodeListIndex(): Int {
    // Prohibit leading comma
    val hasComma = lexer.tryConsumeComma()
    return if (lexer.canConsumeValue()) {
        if (currentIndex != -1 && !hasComma) lexer.fail("Expected end of the array or comma")
        ++currentIndex
    } else {
        if (hasComma && !json.configuration.allowTrailingComma) lexer.invalidTrailingComma("array")
        CompositeDecoder.DECODE_DONE
    }
}

public fun RoutingNode.getAllRoutes(): List<RoutingNode> {
    val endpoints = mutableListOf<RoutingNode>()
    getAllRoutes(endpoints)
    return endpoints
}

private fun RoutingNode.getAllRoutes(endpoints: MutableList<RoutingNode>) {
    if (handlers.isNotEmpty()) {
        endpoints.add(this)
    }
    children.forEach { it.getAllRoutes(endpoints) }
}

