if (keyFieldsArg != null) {
  (keyFieldsArg.value as GQLStringValue).value.parseAsGQLSelections().getOrThrow().forEach { selection ->
    if (selection !is GQLField) {
      registerIssue("Fragments are not supported in @$TYPE_POLICY directives", keyFieldsArg.sourceLocation)
    } else if (selection.selections.isNotEmpty()) {
      registerIssue("Composite fields are not supported in @$TYPE_POLICY directives", keyFieldsArg.sourceLocation)
    } else {
      val definition = fieldDefinitions.firstOrNull { it.name == selection.name }
      if (definition == null) {
        registerIssue("No such field: '$typeName.${selection.name}'", keyFieldsArg.sourceLocation)
      }
    }
  }
}

init {
    val elementsCount = descriptor.elementsCount
    if (elementsCount <= Long.SIZE_BITS) {
        lowerMarks = if (elementsCount == Long.SIZE_BITS) {
            // number of bits in the mark is equal to the number of fields
            0L
        } else {
            // (1 - elementsCount) bits are always 1 since there are no fields for them
            -1L shl elementsCount
        }
        highMarksArray = EMPTY_HIGH_MARKS
    } else {
        lowerMarks = 0L
        highMarksArray = prepareHighMarksArray(elementsCount)
    }
}

public data class PathSegmentConstantRouteSelector(
    val value: String
) : RouteSelector(), RoutePathComponent {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation = when {
        segmentIndex < context.segments.size && context.segments[segmentIndex] == value ->
            RouteSelectorEvaluation.ConstantPath

        else -> RouteSelectorEvaluation.FailedPath
    }

    override fun toString(): String = value
}

public data class HttpMethodRouteSelector(
    val method: HttpMethod
) : RouteSelector() {

    override suspend fun evaluate(context: RoutingResolveContext, segmentIndex: Int): RouteSelectorEvaluation {
        if (context.call.request.httpMethod == method) {
            return RouteSelectorEvaluation.Constant
        }
        return RouteSelectorEvaluation.FailedMethod
    }

    override fun toString(): String = "(method:${method.value})"
}

