  0 -> {
    issues.add(OtherValidationIssue("Cannot find $extra type `${extension.name}` to apply the following extension:\n${extension.toUtf8()}", extension.sourceLocation))
  }

  1 -> {
    val indexedValue = indexedValues.first()
    definitions.set(indexedValue.index, merge(indexedValue.value as T))
  }

  else -> {
    issues.add(OtherValidationIssue("Multiple '${extension.name}' types found while merging extensions.", extension.sourceLocation))
  }
}

if (isOneOfInputObject) {
  if (value.fields.size != 1) {
    registerIssue(
        message = "Exactly one field must be supplied to the OneOf input object `${expectedType.pretty()}`",
        sourceLocation = value.sourceLocation
    )
  } else {
    val valueField = value.fields.first()
    if (valueField.value is GQLNullValue) {
      registerIssue(
          message = "The field `${valueField.name}` supplied to the OneOf input object `${expectedType.pretty()}` must not be null",
          sourceLocation = value.sourceLocation
      )
    }
  }
}

if (enumValue == null) {
  registerIssue(
      message = "Cannot find enum value `${value.value}` of type `${enumTypeDefinition.name}`",
      sourceLocation = value.sourceLocation
  )
} else if (enumValue.isDeprecated()) {
  issues.add(DeprecatedUsage(
      message = "Use of deprecated enum value `${value.value}` of type `${enumTypeDefinition.name}`",
      sourceLocation = value.sourceLocation
  ))
}

if (isOneOfInputObject) {
  if (gqlInputValueDefinition.type is GQLNonNullType) {
    registerIssue("Input field '${gqlInputValueDefinition.name}' of OneOf input object '${o.name}' must be nullable", gqlInputValueDefinition.sourceLocation)
  }
  if (gqlInputValueDefinition.defaultValue != null) {
    registerIssue("Input field '${gqlInputValueDefinition.name}' of OneOf input object '${o.name}' must not have a default value", gqlInputValueDefinition.sourceLocation)
  }
}

if (keyFields.isNotEmpty()) {
  if (distinct.isNotEmpty()) {
    val extra = interfaces.indices.joinToString("\n") {
      "${interfaces[it]}: ${interfacesKeyFields[it]}"
    }

    registerIssue(
        message = "Type '${typeDefinition.name}' cannot have key fields since it implements the following interfaces which also have key fields: $extra",
        sourceLocation = typeDefinition.sourceLocation
    )
  }
  keyFields
} else {
  distinct.firstOrNull() ?: emptySet()
}

